changeSet.sql:
ALTER TABLE config_audit_event DROP CONSTRAINT ck_config_audit_event_entity_type;
ALTER TABLE config_audit_event ADD CONSTRAINT ck_config_audit_event_entity_type
    CHECK (entity_type IN (
        'PRACTICE_REVIEW_SETTINGS', 'AI_CONFIG_BINDING', 'AGENT_CONFIG',
        'WORKSPACE_ROLE', 'WORKSPACE_FEATURES', 'WORKSPACE_STATUS',
        'WORKSPACE_TOKEN', 'WORKSPACE_VISIBILITY', 'PRACTICE_ACTIVE',
        'WORKSPACE_LLM_BUDGET'
    ));

ALTER TABLE llm_connection ADD CONSTRAINT ck_llm_connection_api_protocol
    CHECK (api_protocol IN ('openai-completions','openai-responses'));
ALTER TABLE llm_connection ADD CONSTRAINT ck_llm_connection_auth_mode
    CHECK (auth_mode IN ('BEARER','API_KEY'));

ALTER TABLE workspace_llm_connection ADD CONSTRAINT ck_ws_llm_connection_api_protocol
    CHECK (api_protocol IN ('openai-completions','openai-responses'));
ALTER TABLE workspace_llm_connection ADD CONSTRAINT ck_ws_llm_connection_auth_mode
    CHECK (auth_mode IN ('BEARER','API_KEY'));

ALTER TABLE instance_llm_settings ADD CONSTRAINT ck_instance_llm_settings_singleton CHECK (id = 1);
ALTER TABLE instance_llm_settings ADD CONSTRAINT ck_instance_llm_settings_policy
    CHECK (default_unpriced_policy IN ('WARN','BLOCK'));
INSERT INTO instance_llm_settings (id, allowed_egress_hosts, allow_workspace_connections, default_unpriced_policy)
    VALUES (1, NULL, TRUE, 'WARN') ON CONFLICT (id) DO NOTHING;

ALTER TABLE llm_usage_event ADD CONSTRAINT ck_llm_usage_event_pricing_state
    CHECK (pricing_state IN ('PRICED','NO_CHARGE','UNPRICED'));
ALTER TABLE llm_usage_event ADD CONSTRAINT ck_llm_usage_event_funding_source
    CHECK (funding_source IN ('INSTANCE','WORKSPACE'));
-- Classify migrated history conservatively. A positive cost is genuinely PRICED. A zero cost
-- with NO tokens burned is a genuine no-op -> NO_CHARGE. A zero cost WITH burned tokens is the
-- "runtime didn't price it" trap (see LlmUsageRecorder) and a NULL cost is unknown: both stay
-- UNPRICED (the default) so they surface as unverifiable rather than silently counting as $0.
UPDATE llm_usage_event SET pricing_state = 'PRICED' WHERE cost_usd > 0;
UPDATE llm_usage_event SET pricing_state = 'NO_CHARGE'
    WHERE cost_usd = 0
      AND (input_tokens + output_tokens + cache_read_tokens + cache_write_tokens) = 0;

ALTER TABLE config_audit_event DROP CONSTRAINT ck_config_audit_event_entity_type;
ALTER TABLE config_audit_event ADD CONSTRAINT ck_config_audit_event_entity_type
    CHECK (entity_type IN (
        'PRACTICE_REVIEW_SETTINGS', 'AI_CONFIG_BINDING', 'AGENT_CONFIG',
        'WORKSPACE_ROLE', 'WORKSPACE_FEATURES', 'WORKSPACE_STATUS',
        'WORKSPACE_TOKEN', 'WORKSPACE_VISIBILITY', 'PRACTICE_ACTIVE',
        'WORKSPACE_LLM_BUDGET', 'WORKSPACE_LLM_CONNECTION', 'WORKSPACE_LLM_MODEL'
    ));

CREATE INDEX CONCURRENTLY ix_agent_job_running_config
    ON agent_job (config_id)
    WHERE status = 'RUNNING';

CREATE INDEX CONCURRENTLY ix_agent_job_queued_available
    ON agent_job (available_at, id)
    WHERE status = 'QUEUED';

CREATE INDEX CONCURRENTLY ix_agent_job_delivery_pending
    ON agent_job (completed_at)
    WHERE status = 'COMPLETED' AND delivery_status = 'PENDING';

CREATE INDEX CONCURRENTLY ix_agent_job_retention
    ON agent_job (completed_at)
    WHERE status IN ('COMPLETED','FAILED','TIMED_OUT','CANCELLED');

ALTER TABLE feedback DROP CONSTRAINT sfk_feedback_agent_job;
ALTER TABLE feedback ADD CONSTRAINT sfk_feedback_agent_job
    FOREIGN KEY (agent_job_id) REFERENCES agent_job (id) ON DELETE RESTRICT;

rollback.sql:
ALTER TABLE feedback DROP CONSTRAINT sfk_feedback_agent_job;
ALTER TABLE feedback ADD CONSTRAINT sfk_feedback_agent_job
    FOREIGN KEY (agent_job_id) REFERENCES agent_job (id) ON DELETE CASCADE;

changeSet.sql:
UPDATE agent_config
    SET enabled = false
    WHERE enabled
      AND ((instance_model_id IS NULL) = (workspace_model_id IS NULL));

ALTER TABLE agent_config DROP CONSTRAINT ck_agent_config_single_binding;
ALTER TABLE agent_config ADD CONSTRAINT ck_agent_config_enabled_binding CHECK (
    NOT (instance_model_id IS NOT NULL AND workspace_model_id IS NOT NULL)
    AND (
        NOT enabled
        OR ((instance_model_id IS NOT NULL) <> (workspace_model_id IS NOT NULL))
    )
);

rollback.sql:
ALTER TABLE agent_config DROP CONSTRAINT ck_agent_config_enabled_binding;
ALTER TABLE agent_config ADD CONSTRAINT ck_agent_config_single_binding
    CHECK (NOT (instance_model_id IS NOT NULL AND workspace_model_id IS NOT NULL));

changeSet.sql:
ALTER TABLE llm_usage_event ADD COLUMN source_type VARCHAR(20) NOT NULL DEFAULT 'AGENT_JOB';
ALTER TABLE llm_usage_event ADD COLUMN source_attempt INTEGER NOT NULL DEFAULT 0;
UPDATE llm_usage_event SET source_type = 'MENTOR_TURN' WHERE job_type = 'MENTOR_TURN';
ALTER TABLE llm_usage_event ALTER COLUMN source_type DROP DEFAULT;
ALTER TABLE llm_usage_event DROP CONSTRAINT ux_llm_usage_event_source;
ALTER TABLE llm_usage_event ADD CONSTRAINT ck_llm_usage_event_source_type
    CHECK (source_type IN ('AGENT_JOB','MENTOR_TURN'));
ALTER TABLE llm_usage_event ADD CONSTRAINT ck_llm_usage_event_source_attempt
    CHECK (source_attempt >= 0);
ALTER TABLE llm_usage_event ADD CONSTRAINT ux_llm_usage_event_source_attempt
    UNIQUE (source_type, source_id, source_attempt);

rollback.sql:
ALTER TABLE llm_usage_event DROP CONSTRAINT ux_llm_usage_event_source_attempt;
ALTER TABLE llm_usage_event DROP CONSTRAINT ck_llm_usage_event_source_attempt;
ALTER TABLE llm_usage_event DROP CONSTRAINT ck_llm_usage_event_source_type;
DO $$ BEGIN
    IF EXISTS (SELECT 1 FROM llm_usage_event GROUP BY source_id HAVING count(*) > 1) THEN
        RAISE EXCEPTION 'Cannot roll back attempt-aware LLM ledger without deleting accounting rows';
    END IF;
END $$;
ALTER TABLE llm_usage_event DROP COLUMN source_attempt;
ALTER TABLE llm_usage_event DROP COLUMN source_type;
ALTER TABLE llm_usage_event ADD CONSTRAINT ux_llm_usage_event_source UNIQUE (source_id);
